#include<bits/stdc++.h>
using namespace std;
int n,k,a[262149],b[262149],c[262149];
int msort(int l,int r)
{
    if(l==r)
    {
        return 1;
    }
    int mid=(l+r)/2;
    int tl=msort(l,mid)+l-1;
    int tr=msort(mid+1,r)+mid;
    int nl=l,nr=mid+1,tot=l-1;
    if(a[b[nl]]<a[b[nr]])
    {
        while(nl<=tl&&a[b[nl]]+k<a[b[nr]])
        {
            nl++;
        }
    }
    else
    {
        while(nr<=tr&&a[b[nr]]+k<a[b[nl]])
        {
            nr++;
        }
    }
    while(nl<=tl&&nr<=tr)
    {
        if(a[b[nl]]<a[b[nr]])
        {
            c[++tot]=b[nl++];
        }
        else
        {
            c[++tot]=b[nr++];
        }
    }
    while(nl<=tl)
    {
        c[++tot]=b[nl++];
    }
    while(nr<=tr)
    {
        c[++tot]=b[nr++];
    }
    for(int i=l;i<=tot;i++)
    {
        b[i]=c[i];
    }
    return tot-(l-1);
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%d%d",&n,&k);
        n=(1<<n);
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
            b[i]=i;
        }
        int cnt=msort(1,n),flag=0;
        for(int i=1;i<=cnt;i++)
        {
            if(b[i]==1)
            {
                flag=1;
                break;
            }
        }
        if(flag)
        {
            printf("Kotori\n");
        }
        else
        {
            printf("Yoshino\n");
        }
    }
    return 0;
}
